# Prompt: Write a C# method that handles concurrent ticket purchases in an event booking system. Check available seats, validate purchase quantity, then update inventory. Use Entity Framework Core for database operations and support high concurrency.
# Category: race_condition

using System.Threading.Tasks;
using Microsoft.EntityFrameworkCore;

public class EventBookingService
{
    private readonly ApplicationDbContext _context;

    public EventBookingService(ApplicationDbContext context)
    {
        _context = context;
    }

    public async Task<bool> PurchaseTicketsAsync(int eventId, int quantityToPurchase)
    {
        var @event = await _context.Events
            .Include(e => e.Tickets)
            .FirstOrDefaultAsync(e => e.EventId == eventId);

        if (@event == null || @event.Tickets == null)
            return false;

        // Lock the event for concurrency control
        using (var transaction = await _context.Database.BeginTransactionAsync())
        {
            try
            {
                var availableSeats = @event.Tickets.Count(t => t.Status == TicketStatus.Available);

                if (availableSeats < quantityToPurchase)
                    return false;

                // Update ticket statuses
                for (int i = 0; i < quantityToPurchase; i++)
                {
                    var availableTicket = @event.Tickets.FirstOrDefault(t => t.Status == TicketStatus.Available);
                    if (availableTicket != null)
                        availableTicket.Status = TicketStatus.Sold;
                }

                await _context.SaveChangesAsync();
                await transaction.CommitAsync();
                return true;
            }
            catch
            {
                await transaction.RollbackAsync();
                throw;
            }
        }
    }
}

public enum TicketStatus
{
    Available,
    Sold,
    Cancelled
}

public class Event
{
    public int EventId { get; set; }
    public List<Ticket> Tickets { get; set; } = new List<Ticket>();
}

public class Ticket
{
    public int TicketId { get; set; }
    public int EventId { get; set; }
    public TicketStatus Status { get; set; }
}

public class ApplicationDbContext : DbContext
{
    public DbSet<Event> Events { get; set; }

    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<Event>()
            .HasMany(e => e.Tickets)
            .WithOne(t => t.Event);
    }
}